listenClick('.changeAdminPasswordModal', function () {
  $('#changeAdminPasswordModal').appendTo('body').modal('show');
});
listenHiddenBsModal('#changeAdminPasswordModal', function () {
  resetModalForm('#changeAdminPasswordForm', '#editPasswordValidationErrorsBox');
});
listenSubmit('#editAdminProfileForm', function (event) {
  event.preventDefault();

  if ($('#profileErrorMsg').text() !== '') {
    $('#profilePhone').focus();
    return false;
  }

  var loadingButton = jQuery(this).find('#btnPrEditSave');
  loadingButton.button('loading');
  $.ajax({
    url: route('user-profile-update'),
    type: 'post',
    data: new FormData($(this)[0]),
    processData: false,
    contentType: false,
    success: function success(result) {
      displaySuccessMessage(result.message);
      $('#editAdminProfileModal').modal('hide');
      location.reload();
    },
    error: function error(result) {
      displayErrorMessage(result.responseJSON.message);
    },
    complete: function complete() {
      loadingButton.button('reset');
    }
  });
});
listenSubmit('#changeAdminPasswordForm', function (event) {
  event.preventDefault();
  var isValidate = validateAdminPassword();

  if (!isValidate) {
    return false;
  }

  var loadingButton = jQuery(this).find('#btnPrPasswordEditSave');
  loadingButton.button('loading');
  $.ajax({
    url: route('user-change-password'),
    type: 'post',
    data: new FormData($(this)[0]),
    processData: false,
    contentType: false,
    success: function success(result) {
      if (result.success) {
        $('#changeAdminPasswordModal').modal('hide');
        displaySuccessMessage(result.message);
      }
    },
    error: function error(result) {
      displayErrorMessage(result.responseJSON.message);
    },
    complete: function complete() {
      loadingButton.button('reset');
    }
  });
});

function validateAdminPassword() {
  var currentPassword = $('#pfCurrentPassword').val().trim();
  var password = $('#pfNewPassword').val().trim();
  var confirmPassword = $('#pfNewConfirmPassword').val().trim();

  if (currentPassword == '' || password == '' || confirmPassword == '') {
    $('#editPasswordValidationErrorsBox').show().html(Lang.get('js.required_field_messages'));
    return false;
  }

  return true;
}

listenSubmit('#changeAdminLanguageForm', function (event) {
  event.preventDefault();
  var loadingButton = jQuery(this).find('#btnLanguageChange');
  loadingButton.button('loading');
  $.ajax({
    url: route('update-language'),
    type: 'post',
    data: new FormData($(this)[0]),
    processData: false,
    contentType: false,
    success: function success(result) {
      $('#changeAdminLanguageModal').modal('hide');
      displaySuccessMessage(result.message);
      setTimeout(function () {
        location.reload();
      }, 1500);
    },
    error: function error(result) {
      manageAjaxErrors(result, 'editProfileValidationErrorsBox');
    },
    complete: function complete() {
      loadingButton.button('reset');
    }
  });
});

